parameters.jsCode:
// Parse and validate the AI YouTube metadata output.
const rawContent = $input.first().json?.message?.content
  || $input.first().json?.choices?.[0]?.message?.content
  || '';
const ctx = $('Execute Workflow Trigger').first().json;

let youtube_metadata;
try {
  const cleaned = rawContent.replace(/^```[a-z]*\n?|\n?```$/g, '').trim();
  youtube_metadata = JSON.parse(cleaned);
} catch (e) {
  throw new Error(`Failed to parse YouTube metadata JSON for ${ctx.topic_slug}/${ctx.date_key}: ${e.message}`);
}

// Validate required fields
if (!youtube_metadata.title || youtube_metadata.title.length < 10) {
  throw new Error('YouTube metadata missing or too short title');
}
if (!youtube_metadata.description || youtube_metadata.description.length < 100) {
  throw new Error('YouTube metadata missing or too short description');
}
if (!Array.isArray(youtube_metadata.tags) || youtube_metadata.tags.length < 5) {
  throw new Error('YouTube metadata missing tags (minimum 5 required)');
}

// Enforce limits
youtube_metadata.title = String(youtube_metadata.title).slice(0, 100);
youtube_metadata.description = String(youtube_metadata.description).slice(0, 5000);
youtube_metadata.tags = youtube_metadata.tags
  .slice(0, 15)
  .map(t => String(t).slice(0, 100).toLowerCase().trim())
  .filter(t => t.length >= 2);
youtube_metadata.category = youtube_metadata.category || 'News & Politics';
youtube_metadata.visibility = ['public', 'unlisted', 'private'].includes(youtube_metadata.visibility)
  ? youtube_metadata.visibility
  : 'public';

return [{ json: { ...ctx, youtube_metadata } }];
